firmware_template.source:
#include "dht11.h"
#include <DHT.h>
#define DHT_PIN 4
static DHT dht(DHT_PIN,DHT11);
static float _t=0,_h=0;
static unsigned long _last=0;
void dht11_setup(){dht.begin();Serial.println("[dht11] OK");}
void dht11_loop(){if(millis()-_last<2000)return;_last=millis();_t=dht.readTemperature();_h=dht.readHumidity();}
float dht11_get_temperature(){return _t;}
float dht11_get_humidity(){return _h;}
